@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
}

.mm-wrap {
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.mm-title {
  font-size: 18px;
  font-weight: 700;
  color: #05042E;
}

.mm-field {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.mm-field label {
  font-size: 11px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.mm-field input {
  font-family: "Figtree", sans-serif;
  font-size: 14px;
  font-weight: 600;
  color: #05042E;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 9px 12px;
  outline: none;
}

.mm-field input:focus {
  border-color: #469BC0;
}

.mm-hint {
  font-size: 12px;
  font-weight: 600;
  color: #DC2626;
}

.mm-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 6px;
}

.mm-btn-close {
