  font-weight: 700;
  font-size: 13px;
  color: #469BC0;
  background: #fff;
  border: 1px solid #469BC0;
  border-radius: 6px;
  padding: 9px 18px;
  cursor: pointer;
}

.mm-btn-confirm {
  font-family: "Figtree", sans-serif;
  font-weight: 700;
  font-size: 13px;
  color: #05042E;
  background: #A3E851;
  border: none;
  border-radius: 6px;
  padding: 9px 18px;
  cursor: pointer;
}

.mm-btn-confirm:hover {
  background: #93d846;
}

srcDoc.js:
window.mmConfirm = function () {
  const name = document.getElementById('mm-name').value.trim();
  const weight = document.getElementById('mm-weight').value;
  appsmith.updateModel({
    modelName: name,
    modelWeight: weight
  });
  appsmith.triggerEvent('onConfirm');
};
window.mmClose = function () {
  appsmith.triggerEvent('onClose');
};
function clearFields() {
  document.getElementById('mm-name').value = '';
  document.getElementById('mm-weight').value = '';
}
appsmith.onReady(function () {
  clearFields();
});

